import React from 'react';

/**
 * AccessDenied Component - Shows access denial reasons with clear messaging
 * Used when users are denied access due to location, expiry, or permissions
 */
function AccessDenied({ reason, type = 'default', onRetry = null }) {
  const getIcon = () => {
    switch (type) {
      case 'location':
        return '📍';
      case 'expired':
        return '⏱️';
      case 'permission':
        return '🔒';
      case 'network':
        return '🌐';
      default:
        return '⚠️';
    }
  };

  const getTitle = () => {
    switch (type) {
      case 'location':
        return 'Location Access Denied';
      case 'expired':
        return 'Access Expired';
      case 'permission':
        return 'Permission Denied';
      case 'network':
        return 'Connection Error';
      default:
        return 'Access Denied';
    }
  };

  const getDescription = () => {
    switch (type) {
      case 'location':
        return 'Your current location is outside the allowed access area.';
      case 'expired':
        return 'Your access to this file has expired.';
      case 'permission':
        return 'You do not have permission to access this file.';
      case 'network':
        return 'Unable to verify your location. Please check your internet connection.';
      default:
        return 'Your access request could not be processed.';
    }
  };

  const getColor = () => {
    switch (type) {
      case 'location':
        return 'red';
      case 'expired':
        return 'orange';
      case 'permission':
        return 'purple';
      case 'network':
        return 'yellow';
      default:
        return 'gray';
    }
  };

  const colorMap = {
    red: { bg: 'bg-red-50', border: 'border-red-300', text: 'text-red-800', button: 'bg-red-600 hover:bg-red-700' },
    orange: { bg: 'bg-orange-50', border: 'border-orange-300', text: 'text-orange-800', button: 'bg-orange-600 hover:bg-orange-700' },
    purple: { bg: 'bg-purple-50', border: 'border-purple-300', text: 'text-purple-800', button: 'bg-purple-600 hover:bg-purple-700' },
    yellow: { bg: 'bg-yellow-50', border: 'border-yellow-300', text: 'text-yellow-800', button: 'bg-yellow-600 hover:bg-yellow-700' },
    gray: { bg: 'bg-gray-50', border: 'border-gray-300', text: 'text-gray-800', button: 'bg-gray-600 hover:bg-gray-700' }
  };

  const colors = colorMap[getColor()];

  return (
    <div className={`w-full max-w-md mx-auto p-6 rounded-lg border-2 ${colors.bg} ${colors.border}`}>
      <div className="flex items-center gap-3 mb-4">
        <span className="text-4xl">{getIcon()}</span>
        <h3 className={`text-2xl font-bold ${colors.text}`}>{getTitle()}</h3>
      </div>

      <p className={`text-sm mb-4 ${colors.text}`}>{getDescription()}</p>

      {reason && (
        <div className="bg-white bg-opacity-50 border-l-4 border-current p-3 mb-4 rounded">
          <p className={`text-xs font-semibold ${colors.text} mb-1`}>Details:</p>
          <p className={`text-sm ${colors.text}`}>{reason}</p>
        </div>
      )}

      <div className="space-y-2">
        {onRetry && (
          <button
            onClick={onRetry}
            className={`w-full text-white px-4 py-2 rounded-lg shadow transition text-sm font-semibold ${colors.button}`}
          >
            Try Again
          </button>
        )}
        <button
          onClick={() => window.history.back()}
          className="w-full bg-gray-500 hover:bg-gray-600 text-white px-4 py-2 rounded-lg shadow transition text-sm font-semibold"
        >
          Go Back
        </button>
      </div>

      {type === 'location' && (
        <div className="mt-4 p-3 bg-white bg-opacity-50 rounded text-xs text-gray-700">
          <p className="font-semibold mb-1">💡 Need access from a different location?</p>
          <p>Contact the file owner to update your access permissions.</p>
        </div>
      )}

      {type === 'expired' && (
        <div className="mt-4 p-3 bg-white bg-opacity-50 rounded text-xs text-gray-700">
          <p className="font-semibold mb-1">💡 Access no longer available?</p>
          <p>Request access again from the file owner.</p>
        </div>
      )}
    </div>
  );
}

export default AccessDenied;
